  const bankSource = quizzes["SUR 401-1 MCQs"].sources[0]
  const summarizeSections = (partQuestions) => {
    const sections = [...new Set(partQuestions.map((question) => question.section).filter(Boolean))]
    if (!sections.length) return "Source-order questions"
    if (sections.length === 1) return sections[0]
    if (sections.length === 2) return `${sections[0]} ? ${sections[1]}`
    return `${sections[0]} ? ${sections[sections.length - 1]}`
  }

  bankSource.collection = {
    mixedSizes: [
      { id: "quick-20", label: "Quick 20", size: 20, description: "A short mixed revision session." },
      { id: "standard-30", label: "Standard 30", size: 30, description: "Balanced mixed practice." },
      { id: "exam-50", label: "Exam 50", size: 50, description: "A longer exam-style revision set." }
    ],
    wrongReviewId: "kellawi-wrong-review",
    groups: organDefinitions.map((definition) => {
      const organQuestions = bankSource.mcqs.filter((question) => question.organ === definition.label)
      let offset = 0
      const parts = definition.sizes.map((size, index) => {
        const start = offset + 1
        const end = offset + size
        const partQuestions = organQuestions.slice(offset, end)
        offset = end
        return {
          id: `kellawi-${definition.id}-p${String(index + 1).padStart(2, "0")}`,
          label: `Part ${index + 1} ? Q${start}?${end}`,
          description: summarizeSections(partQuestions),
          range: `Q${start}?${end}`,
          questionStart: start,
          questionEnd: end,
          parentSourceId: bankSource.id,
          groupId: definition.id,
          groupLabel: definition.label,
          partIndex: index,
          partCount: definition.sizes.length,
          shuffleQuestions: false,
          shuffleOptions: false,
          mcqs: partQuestions
        }
      })
      return {
        id: definition.id,
        label: definition.label,
        questionCount: organQuestions.length,
        parts
      }
    })
  }
